/**
 * Static HTML page generator for KNTIC Links.
 *
 * Produces a single, fully self-contained index.html with all CSS inlined.
 * No JavaScript in the output — works with JS disabled.
 */

import { readFileSync } from 'node:fs';
import { resolve, dirname, extname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { isLinkActive } from './utils.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** HTML-escape a string to prevent XSS. */
function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/** MIME type lookup for common image formats. */
function imageMime(filePath) {
  const ext = extname(filePath).toLowerCase();
  const map = {
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.webp': 'image/webp',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
    '.avif': 'image/avif',
  };
  return map[ext] || 'application/octet-stream';
}

/**
 * Read a local image file and return a base64 data URI.
 * @param {string} filePath — path to the image (absolute or relative to configDir)
 * @param {string} configDir — directory that links.yaml lives in
 * @returns {string} data URI string
 */
export function inlineImage(filePath, configDir) {
  const abs = resolve(configDir, filePath);
  const buf = readFileSync(abs);
  const mime = imageMime(abs);
  return `data:${mime};base64,${buf.toString('base64')}`;
}

// ---------------------------------------------------------------------------
// Schedule filtering
// ---------------------------------------------------------------------------

/**
 * Filter links to only those whose schedule window includes `now`.
 * Links without scheduling fields are always included.
 * Delegates to isLinkActive() from utils.js for per-link evaluation.
 */
export function filterScheduled(links, now = new Date()) {
  if (!links || !Array.isArray(links)) return [];
  return links.filter((link) => isLinkActive(link, now));
}

// ---------------------------------------------------------------------------
// Theme CSS loading
// ---------------------------------------------------------------------------

/**
 * Load theme CSS from the themes directory.
 * @param {string} themeName — name without .css extension
 * @returns {string} CSS content
 */
export function loadThemeCSS(themeName) {
  const themePath = resolve(__dirname, 'themes', `${themeName}.css`);
  try {
    return readFileSync(themePath, 'utf8');
  } catch {
    throw new Error(
      `Theme "${themeName}" not found at ${themePath}. ` +
      'Available themes live in src/themes/.',
    );
  }
}

// ---------------------------------------------------------------------------
// HTML generation
// ---------------------------------------------------------------------------

/**
 * Generate a complete, self-contained HTML page from a links config.
 *
 * @param {object} config — parsed links.yaml config object
 * @param {object} [options]
 * @param {string} [options.configDir=process.cwd()] — directory links.yaml lives in (for resolving relative paths)
 * @param {Date}   [options.now=new Date()]           — current time (for schedule filtering)
 * @returns {string} Complete HTML document
 */
export function generatePage(config, options = {}) {
  const configDir = options.configDir || process.cwd();
  const now = options.now || new Date();

  const name = config.name || 'My Links';
  const bio = config.bio || '';
  const theme = config.theme || 'minimal-dark';

  // Load and inline CSS
  const css = loadThemeCSS(theme);

  // Filter links by schedule
  const allLinks = config.links || [];
  const links = filterScheduled(allLinks, now);
  const totalCount = allLinks.length;
  const activeCount = links.length;
  const buildDate = now.toISOString().slice(0, 10);

  // Avatar handling
  let avatarHTML = '';
  if (config.avatar && config.avatar.trim().length > 0) {
    try {
      const dataUri = inlineImage(config.avatar, configDir);
      avatarHTML = `<img class="profile__avatar" src="${dataUri}" alt="${esc(name)}" width="88" height="88">`;
    } catch {
      // Fallback: reference the file directly (it will be copied to output dir)
      avatarHTML = `<img class="profile__avatar" src="${esc(config.avatar)}" alt="${esc(name)}" width="88" height="88">`;
    }
  }

  // Build link list HTML
  const linksHTML = links.map((link) => {
    const icon = link.icon ? `<span class="links__icon">${esc(link.icon)}</span>` : '';
    const description = link.description
      ? `<span class="links__description">${esc(link.description)}</span>`
      : '';

    return `      <li class="links__item">
        <a class="links__anchor" href="${esc(link.url)}" target="_blank" rel="noopener noreferrer">
          <span class="links__label">${icon}${esc(link.label)}</span>${description}
        </a>
      </li>`;
  }).join('\n');

  // OG description falls back to bio, then a generic string
  const ogDescription = bio || `${name} — link page`;

  return `<!DOCTYPE html>
<!-- built at ${buildDate}, ${activeCount} of ${totalCount} links active -->
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${esc(name)}</title>
  <meta name="description" content="${esc(ogDescription)}">
  <meta property="og:title" content="${esc(name)}">
  <meta property="og:description" content="${esc(ogDescription)}">
  <meta property="og:type" content="website">
  <style>
${css}
  </style>
</head>
<body>
  <section class="profile">
    ${avatarHTML}
    <h1 class="profile__name">${esc(name)}</h1>
${bio ? `    <p class="profile__bio">${esc(bio)}</p>\n` : ''}  </section>

  <ul class="links">
${linksHTML}
  </ul>

  <footer class="footer">
    <a class="footer__link" href="https://kntic.ai">Powered by KNTIC Links</a>
  </footer>
</body>
</html>
`;
}

/**
 * Shared utility helpers for @kntic/links.
 */

import { readFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import yaml from 'js-yaml';

/**
 * Default config filename.
 */
export const CONFIG_FILE = 'links.yml';

/**
 * Load and parse the links YAML config from the current directory.
 * @param {string} [dir=process.cwd()] - Directory to look in.
 * @returns {Promise<object>} Parsed config object.
 */
export async function loadConfig(dir = process.cwd()) {
  const filePath = resolve(dir, CONFIG_FILE);
  const raw = await readFile(filePath, 'utf8');
  return yaml.load(raw);
}

/**
 * Pretty-print an error and exit.
 * @param {string} message
 * @param {number} [code=1]
 */
export function fatal(message, code = 1) {
  console.error(`error: ${message}`);
  process.exit(code);
}

// ---------------------------------------------------------------------------
// Link scheduling
// ---------------------------------------------------------------------------

/**
 * Determine whether a link is currently active based on its scheduling fields.
 *
 * Rules:
 *   - No dates → always active
 *   - Only scheduled_from → active from that date onwards (inclusive, >=)
 *   - Only scheduled_until → active until that date (inclusive, <=)
 *   - Both → active within the window [scheduled_from, scheduled_until]
 *
 * All comparisons are performed in UTC using Date.parse().
 *
 * @param {object} link — a link object that may contain scheduled_from / scheduled_until
 * @param {Date}   [now=new Date()] — reference time for the comparison
 * @returns {boolean} true if the link should be included in the current build
 */
export function isLinkActive(link, now = new Date()) {
  if (!link || typeof link !== 'object') return false;

  const ts = now.getTime();

  if (link.scheduled_from) {
    const from = Date.parse(link.scheduled_from);
    if (!Number.isNaN(from) && ts < from) return false;
  }

  if (link.scheduled_until) {
    const until = Date.parse(link.scheduled_until);
    // Inclusive: if only a date (YYYY-MM-DD) is given, Date.parse returns
    // midnight UTC — we treat the entire day as included, so we compare
    // against the end of that day (start-of-next-day minus 1 ms) only when
    // the value looks like a bare date (10 chars, no time component).
    if (!Number.isNaN(until)) {
      const untilEnd =
        typeof link.scheduled_until === 'string' && link.scheduled_until.length === 10
          ? until + 86_400_000 - 1  // end of day
          : until;
      if (ts > untilEnd) return false;
    }
  }

  return true;
}

/* minimal-dark — default KNTIC Links theme
 *
 * Clean, modern dark. No gradients, no gimmicks.
 * This is what most users will ship.
 */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  /* Backgrounds */
  --bg-color: #0f0f0f;
  --bg-secondary: #1a1a1a;

  /* Text */
  --text-primary: #f0f0f0;
  --text-secondary: #b0b0b0;
  --text-muted: #787878;

  /* Accent — muted violet */
  --accent-color: #c4b5fd;
  --accent-hover: #ddd6fe;

  /* Link cards */
  --link-bg: var(--bg-secondary);
  --link-bg-hover: #242424;
  --link-border: #2a2a2a;
  --link-radius: 10px;
  --link-padding: 0.875rem 1.25rem;

  /* Typography */
  --font-body: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  --font-mono: 'SF Mono', 'Fira Code', 'Cascadia Code', monospace;

  /* Avatar */
  --avatar-radius: 50%;

  /* Layout */
  --page-max-width: 480px;

  /* Footer */
  --footer-opacity: 0.5;
}

html {
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-body);
  background-color: var(--bg-color);
  color: var(--text-primary);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 3rem 1rem 1rem;
  line-height: 1.5;
}

/* ── Profile ─────────────────────────────────────────────────────── */

.profile {
  text-align: center;
  margin-bottom: 2rem;
  max-width: var(--page-max-width);
  width: 100%;
}

.profile__avatar {
  width: 88px;
  height: 88px;
  border-radius: var(--avatar-radius);
  object-fit: cover;
  margin-bottom: 0.75rem;
  border: 2px solid var(--link-border);
}

.profile__name {
  font-size: 1.3rem;
  font-weight: 600;
  margin-bottom: 0.3rem;
  color: var(--text-primary);
  letter-spacing: -0.01em;
}

.profile__bio {
  font-size: 0.9rem;
  color: var(--text-muted);
  max-width: 320px;
  margin: 0 auto;
}

/* ── Links ───────────────────────────────────────────────────────── */

.links {
  list-style: none;
  width: 100%;
  max-width: var(--page-max-width);
  display: flex;
  flex-direction: column;
  gap: 0.625rem;
}

.links__item {
  display: block;
  width: 100%;
}

.links__anchor {
  display: block;
  width: 100%;
  padding: var(--link-padding);
  background-color: var(--link-bg);
  border: 1px solid var(--link-border);
  border-radius: var(--link-radius);
  color: var(--accent-color);
  text-decoration: none;
  text-align: center;
  transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
}

.links__anchor:hover,
.links__anchor:focus {
  background-color: var(--link-bg-hover);
  color: var(--accent-hover);
  border-color: #3a3a3a;
  outline: none;
}

.links__label {
  font-size: 0.95rem;
  font-weight: 500;
}

.links__icon {
  margin-right: 0.4em;
}

.links__description {
  display: block;
  font-size: 0.8rem;
  color: var(--text-secondary);
  margin-top: 0.2rem;
}

/* ── Footer ──────────────────────────────────────────────────────── */

.footer {
  margin-top: auto;
  padding-top: 2rem;
  padding-bottom: 1rem;
  text-align: center;
}

.footer__link {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-decoration: none;
  opacity: var(--footer-opacity);
  transition: opacity 0.2s ease;
}

.footer__link:hover {
  opacity: 1;
}

